class Solution:
    def regionsBySlashes(self, grid):
        """
        :type grid: List[str]
        :rtype: int
        """
        n = len(grid)
        # Each cell expands to 3x3
        expanded = [[0] * (3*n) for _ in range(3*n)]

        for i in range(n):
            for j in range(n):
                if grid[i][j] == '/':
                    expanded[3*i][3*j+2] = 1
                    expanded[3*i+1][3*j+1] = 1
                    expanded[3*i+2][3*j] = 1
                elif grid[i][j] == '\\':
                    expanded[3*i][3*j] = 1
                    expanded[3*i+1][3*j+1] = 1
                    expanded[3*i+2][3*j+2] = 1

        # Count regions using BFS/DFS
        visited = [[False] * (3*n) for _ in range(3*n)]
        regions = 0

        for i in range(3*n):
            for j in range(3*n):
                if not visited[i][j] and expanded[i][j] == 0:
                    regions += 1
                    stack = [(i, j)]
                    while stack:
                        r, c = stack.pop()
                        if r < 0 or r >= 3*n or c < 0 or c >= 3*n:
                            continue
                        if visited[r][c] or expanded[r][c] == 1:
                            continue
                        visited[r][c] = True
                        for dr, dc in [(0,1), (0,-1), (1,0), (-1,0)]:
                            stack.append((r+dr, c+dc))

        return regions
